// core/tree/components/CoreTreeSelect.tsx

import React, { useMemo, useState } from 'react';
import {
  View,
  Text,
  Pressable,
  Modal,
  ScrollView,
  StyleSheet,
} from 'react-native';
import { ChevronDown, X } from 'lucide-react-native';

import type {
  TreeSelectProps,
  SelectionValue,
  TreeNode,
  TreeSelectChangeEvent,
} from '../types';
import { createTreeEvent } from '../engine/TreeEvents';
import CoreTree from './CoreTree';
import { resolveThemeTokenForNative } from '../../../Factory/helpers/style';

const t = resolveThemeTokenForNative;

/* ------------------------------------------------------------------ */
/* TreeSelect Component                                                 */
/* ------------------------------------------------------------------ */

const CoreTreeSelect: React.FC<TreeSelectProps<any>> = (props) => {
  const {
    value,
    options,
    onChange,
    selectionMode = 'single',
    metaKeySelection,
    display = 'comma',
    placeholder = 'Select',
    showClear,
    filter,
    filterBy,
    filterMode,
    filterPlaceholder,
    resetFilterOnHide,
    expandedKeys,
    onToggle,
    disabled,
    invalid,
    variant = 'outlined',
    isModal = true,
    panelHeaderTemplate,
    panelFooterTemplate,
    nodeTemplate,
    emptyMessage,
    scrollHeight,
    onShow,
    onHide,
    onlyParentsWithChildren,
    className,
    style,
  } = props;

  const [open, setOpen] = useState(false);
  const [focused, setFocused] = useState(false);
  const [internalFilterValue, setInternalFilterValue] = useState('');

  const colors = {
    primary: t('primary'),
    primaryDark: t('blue.600'),
    primaryLight: t('blue.50'),
    text: t('gray.700'),
    textSecondary: t('gray.500'),
    placeholder: t('gray.500'),
    border: t('gray.300'),
    borderFocus: t('primary'),
    surface: '#ffffff',
    hover: t('gray.200'),
    invalid: t('red.500'),
    chip: t('gray.300'),
    chipText: t('gray.700'),
    overlay: 'rgba(0, 0, 0, 0.4)',
  };

  const handleOpen = () => {
    setOpen(true);
    setFocused(true);
    onShow?.();
  };

  const handleClose = () => {
    setOpen(false);
    setFocused(false);
    if (resetFilterOnHide) setInternalFilterValue('');
    onHide?.();
  };

  /* ---- Label resolution ---- */

  const nodeMap = useMemo(() => {
    const map = new Map<string, TreeNode>();
    const walk = (nodes?: TreeNode[]) => {
      nodes?.forEach((n) => {
        map.set(n.key, n);
        walk(n.children);
      });
    };
    walk(options);
    return map;
  }, [options]);

  const selectedLabels = useMemo(() => {
    if (!value || !options) return [];

    if (typeof value === 'string') {
      const node = nodeMap.get(value);
      return node?.label ? [node.label] : [];
    }

    if (value && typeof value === 'object') {
      return Object.keys(value)
        .filter((k) => {
          const v: any = (value as any)[k];
          if (!(v === true || v?.checked)) return false;
          // Skip partial-only entries
          if (v?.partialChecked && !v?.checked) return false;
          // Only show labels for selectable nodes
          const node = nodeMap.get(k);
          if (node && node.selectable === false) return false;
          return true;
        })
        .map((k) => nodeMap.get(k)?.label)
        .filter(Boolean) as string[];
    }

    return [];
  }, [value, options, nodeMap]);

  const hasValue = selectedLabels.length > 0;

  /* ---- Handlers ---- */

  const handleChange = (next: SelectionValue, originalEvent?: any) => {
    const event: TreeSelectChangeEvent = {
      originalEvent,
      value: next,
    };
    onChange?.(event);
  };

  const clearSelection = () => {
    handleChange(selectionMode === 'single' ? null : null);
  };

  /* ---- Display value ---- */

  const renderDisplayValue = () => {
    if (!hasValue) {
      return <Text style={[styles.placeholder, { color: colors.placeholder }]}>{placeholder}</Text>;
    }

    if (display === 'chip') {
      return (
        <View style={styles.chipContainer}>
          {selectedLabels.map((label, i) => (
            <View key={i} style={[styles.chip, { backgroundColor: colors.chip }]}>
              <Text style={[styles.chipText, { color: colors.chipText }]} numberOfLines={1}>{label}</Text>
            </View>
          ))}
        </View>
      );
    }

    // comma display
    return (
      <Text style={[styles.valueText, { color: colors.text }]} numberOfLines={1}>
        {selectedLabels.join(', ')}
      </Text>
    );
  };

  /* ---- Panel content ---- */

  const Panel = (
    <View style={styles.panel}>
      {/* Panel header */}
      {panelHeaderTemplate && (
        <View style={[styles.panelHeader, { borderBottomColor: colors.border }]}>
          {typeof panelHeaderTemplate === 'function'
            ? panelHeaderTemplate()
            : panelHeaderTemplate}
        </View>
      )}

      {/* Tree */}
      <ScrollView
        style={{ maxHeight: scrollHeight ?? 350 }}
        nestedScrollEnabled
      >
        <CoreTree
          value={options}
          selectionMode={selectionMode}
          selectionKeys={value}
          metaKeySelection={metaKeySelection}
          expandedKeys={expandedKeys}
          onToggle={onToggle}
          filter={filter}
          filterValue={internalFilterValue}
          filterBy={filterBy}
          filterMode={filterMode}
          filterPlaceholder={filterPlaceholder}
          nodeTemplate={nodeTemplate}
          emptyMessage={emptyMessage}
          onlyParentsWithChildren={onlyParentsWithChildren}
          onSelectionChange={(e) => {
            handleChange(e.value, e.originalEvent);
            // Close on single selection
            if (!selectionMode || selectionMode === 'single') {
              handleClose();
            }
          }}
          style={{ borderWidth: 0, borderRadius: 0 }}
        />
      </ScrollView>

      {/* Panel footer */}
      {panelFooterTemplate && (
        <View style={[styles.panelFooter, { borderTopColor: colors.border }]}>
          {typeof panelFooterTemplate === 'function'
            ? panelFooterTemplate()
            : panelFooterTemplate}
        </View>
      )}
    </View>
  );

  /* ---- Main render ---- */

  return (
    <View style={[{ width: '100%' }, style]} className={className}>
      {/* Input trigger */}
      <Pressable
        disabled={disabled}
        onPress={handleOpen}
        style={[
          styles.input,
          { borderColor: colors.border, backgroundColor: colors.surface },
          variant === 'filled' && { backgroundColor: '#f8f9fa', borderColor: 'transparent', borderBottomColor: colors.border, borderRadius: 0, borderTopLeftRadius: 6, borderTopRightRadius: 6 },
          focused && { borderColor: colors.borderFocus },
          invalid && { borderColor: colors.invalid },
          disabled && { opacity: 0.6, backgroundColor: t('gray.200') },
        ]}
      >
        <View style={styles.inputValueContainer}>
          {renderDisplayValue()}
        </View>

        <View style={styles.inputIcons}>
          {/* Clear button */}
          {showClear && hasValue && !disabled && (
            <Pressable
              onPress={(e) => {
                e.stopPropagation?.();
                clearSelection();
              }}
              hitSlop={8}
              style={styles.clearButton}
            >
              <X size={14} color={colors.textSecondary} />
            </Pressable>
          )}

          {/* Dropdown arrow */}
          <View style={styles.dropdownIcon}>
            <ChevronDown size={16} color={colors.textSecondary} />
          </View>
        </View>
      </Pressable>

      {/* Modal overlay */}
      {isModal ? (
        <Modal
          visible={open}
          transparent
          animationType="fade"
          onRequestClose={handleClose}
        >
          <Pressable
            style={[styles.overlay, { backgroundColor: colors.overlay }]}
            onPress={handleClose}
          >
            <Pressable
              onPress={() => {}} // prevent close on panel press
              style={[styles.modalPanel, { backgroundColor: colors.surface }]}
            >
              {/* Close button */}
              <View style={[styles.modalHeader, { borderBottomColor: colors.border }]}>
                <Text style={[styles.modalHeaderText, { color: colors.text }]}>
                  {placeholder}
                </Text>
                <Pressable
                  onPress={handleClose}
                  hitSlop={8}
                >
                  <X size={20} color={colors.textSecondary} />
                </Pressable>
              </View>
              {Panel}
            </Pressable>
          </Pressable>
        </Modal>
      ) : (
        open && (
          <View style={StyleSheet.absoluteFill} pointerEvents="box-none">
            {/* Backdrop */}
            <Pressable
              style={styles.inlineBackdrop}
              onPress={handleClose}
            />
            {/* Dropdown panel */}
            <View style={[styles.inlinePanel, { backgroundColor: colors.surface, borderColor: colors.border }]}>
              {Panel}
            </View>
          </View>
        )
      )}
    </View>
  );
};

/* ------------------------------------------------------------------ */
/* Styles (layout only — colors applied inline via theme tokens)       */
/* ------------------------------------------------------------------ */

const styles = StyleSheet.create({
  // Input
  input: {
    flexDirection: 'row',
    alignItems: 'center',
    minHeight: 42,
    borderWidth: 1,
    borderRadius: 6,
    paddingLeft: 12,
    paddingRight: 8,
    paddingVertical: 4,
  },
  inputValueContainer: {
    flex: 1,
    marginRight: 4,
  },
  inputIcons: {
    flexDirection: 'row',
    alignItems: 'center',
    gap: 4,
  },

  // Placeholder / value
  placeholder: {
    fontSize: 14,
  },
  valueText: {
    fontSize: 14,
  },

  // Chips
  chipContainer: {
    flexDirection: 'row',
    flexWrap: 'wrap',
    gap: 4,
  },
  chip: {
    flexDirection: 'row',
    alignItems: 'center',
    paddingHorizontal: 8,
    paddingVertical: 3,
    borderRadius: 16,
  },
  chipText: {
    fontSize: 13,
  },

  // Clear / dropdown icons
  clearButton: {
    padding: 4,
  },
  dropdownIcon: {
    padding: 4,
  },

  // Overlay (modal)
  overlay: {
    flex: 1,
    justifyContent: 'center',
  },
  modalPanel: {
    marginHorizontal: 20,
    borderRadius: 8,
    maxHeight: '70%',
    overflow: 'hidden',
    shadowColor: '#000',
    shadowOffset: { width: 0, height: 4 },
    shadowOpacity: 0.15,
    shadowRadius: 12,
    elevation: 8,
  },
  modalHeader: {
    flexDirection: 'row',
    justifyContent: 'space-between',
    alignItems: 'center',
    paddingHorizontal: 16,
    paddingVertical: 12,
    borderBottomWidth: 1,
  },
  modalHeaderText: {
    fontSize: 16,
    fontWeight: '600',
  },

  // Panel
  panel: {
    flex: 1,
  },
  panelHeader: {
    borderBottomWidth: 1,
    padding: 8,
  },
  panelFooter: {
    borderTopWidth: 1,
    padding: 8,
  },

  // Inline dropdown
  inlineBackdrop: {
    ...StyleSheet.absoluteFillObject,
    backgroundColor: 'transparent',
    zIndex: 1,
  },
  inlinePanel: {
    position: 'absolute',
    top: 46,
    left: 0,
    right: 0,
    borderWidth: 1,
    borderRadius: 6,
    zIndex: 2,
    overflow: 'hidden',
    shadowColor: '#000',
    shadowOffset: { width: 0, height: 4 },
    shadowOpacity: 0.1,
    shadowRadius: 8,
    elevation: 4,
  },
});

export default CoreTreeSelect;
